{"content":"//! ALPN (Application-Layer Protocol Negotiation) protocols for QUIC

use std::fmt;

/// Supported ALPN protocols for QUIC
#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub enum AlpnProtocol {
    /// HTTP/3 over QUIC (standardized)
    H3,
    /// HTTP/2 over TLS (for comparison/testing)
    H2,
    /// QUIC interop testing protocol
    HqInterop,
    /// Custom HTX over QUIC (Betanet)
    HtxQuic,
    /// Custom protocol identifier
    Custom(Vec<u8>),
}

impl AlpnProtocol {
    /// Get the ALPN wire format as bytes
    pub fn as_bytes(&self) -> &[u8] {
        match self {
            AlpnProtocol::H3 => b"h3",
            AlpnProtocol::H2 => b"h2",
            AlpnProtocol::HqInterop => b"hq-interop",
            AlpnProtocol::HtxQuic => b"htxquic",
            AlpnProtocol::Custom(bytes) => bytes,
        }
    }

    /// Parse ALPN protocol from wire bytes
    pub fn from_bytes(bytes: &[u8]) -> Option<Self> {
        match bytes {
            b"h3" => Some(AlpnProtocol::H3),
            b"h2" => Some(AlpnProtocol::H2),
            b"hq-interop" => Some(AlpnProtocol::HqInterop),
            b"htxquic" => Some(AlpnProtocol::HtxQuic),
            other => Some(AlpnProtocol::Custom(other.to_vec())),
        }
    }

    /// Get all supported protocols for ALPN negotiation
    pub fn supported_protocols() -> Vec<Self> {
        vec![
            AlpnProtocol::H3,
            AlpnProtocol::HqInterop,
            AlpnProtocol::HtxQuic,
        ]
    }

    /// Get protocols as Vec<Vec<u8>> for rustls configuration
    pub fn to_alpn_vec(protocols: &[Self]) -> Vec<Vec<u8>> {
        protocols.iter().map(|p| p.as_bytes().to_vec()).collect()
    }

    /// Check if this is an HTTP protocol (H2 or H3)
    pub fn is_http(&self) -> bool {
        matches!(self, AlpnProtocol::H2 | AlpnProtocol::H3)
    }

    /// Check if this is a QUIC-native protocol
    pub fn is_quic(&self) -> bool {
        matches!(
            self,
            AlpnProtocol::H3 | AlpnProtocol::HqInterop | AlpnProtocol::HtxQuic
        )
    }
}

impl fmt::Display for AlpnProtocol {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            AlpnProtocol::H3 => write!(f, "h3"),
            AlpnProtocol::H2 => write!(f, "h2"),
            AlpnProtocol::HqInterop => write!(f, "hq-interop"),
            AlpnProtocol::HtxQuic => write!(f, "htxquic"),
            AlpnProtocol::Custom(_) => write!(f, "custom"),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_protocol_bytes() {
        assert_eq!(AlpnProtocol::H3.as_bytes(), b"h3");
        assert_eq!(AlpnProtocol::H2.as_bytes(), b"h2");
        assert_eq!(AlpnProtocol::HqInterop.as_bytes(), b"hq-interop");
    }

    #[test]
    fn test_from_bytes() {
        assert_eq!(AlpnProtocol::from_bytes(b"h3"), Some(AlpnProtocol::H3));
        assert_eq!(AlpnProtocol::from_bytes(b"h2"), Some(AlpnProtocol::H2));
    }

    #[test]
    fn test_is_http() {
        assert!(AlpnProtocol::H3.is_http());
        assert!(AlpnProtocol::H2.is_http());
        assert!(!AlpnProtocol::HqInterop.is_http());
    }

    #[test]
    fn test_is_quic() {
        assert!(AlpnProtocol::H3.is_quic());
        assert!(AlpnProtocol::HqInterop.is_quic());
        assert!(!AlpnProtocol::H2.is_quic());
    }
}
