{"content":"//! Self-signed certificate generation for QUIC server testing
//!
//! Uses rcgen to generate X.509 certificates with TLS 1.3 support

use rustls::pki_types::{CertificateDer, PrivateKeyDer, PrivatePkcs8KeyDer};
use std::sync::Arc;

/// Certificate chain with private key for TLS
pub struct CertificateChain {
    /// End-entity certificate
    pub cert: CertificateDer<'static>,
    /// Private key (PKCS#8 format)
    pub key: PrivateKeyDer<'static>,
    /// Optional intermediate certificates
    pub intermediates: Vec<CertificateDer<'static>>,
}

impl CertificateChain {
    /// Generate a self-signed certificate for localhost testing
    pub fn localhost() -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let cert_params = rcgen::CertificateParams::new(vec![
            "localhost".to_string(),
            "127.0.0.1".to_string(),
            "::1".to_string(),
        ])?;

        let cert = rcgen::Certificate::from_params(cert_params)?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Generate a self-signed certificate for a specific domain
    pub fn for_domain(domain: &str) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let cert_params = rcgen::CertificateParams::new(vec![domain.to_string()])?;
        let cert = rcgen::Certificate::from_params(cert_params)?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Generate a self-signed certificate with custom subject alternative names
    pub fn with_san(sans: Vec<String>) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let cert_params = rcgen::CertificateParams::new(sans)?;
        let cert = rcgen::Certificate::from_params(cert_params)?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Get certificate chain as rustls format
    pub fn to_rustls_certs(&self) -> Vec<CertificateDer<'static>> {
        let mut certs = vec![self.cert.clone()];
        certs.extend(self.intermediates.iter().cloned());
        certs
    }

    /// Get private key as rustls format
    pub fn to_rustls_key(&self) -> PrivateKeyDer<'static> {
        self.key.clone_key()
    }
}

/// Load certificate from PEM file
pub fn load_cert_pem(path: &str) -> Result<CertificateDer<'static>, std::io::Error> {
    let pem_data = std::fs::read(path)?;
    let mut reader = &pem_data[..];

    // Use rustls-pemfile to parse
    let certs = rustls_pemfile::certs(&mut reader);
    let mut cert_iter = certs.collect::<Result<Vec<_>, _>>()
        .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;

    cert_iter.pop().ok_or_else(|| {
        std::io::Error::new(std::io::ErrorKind::InvalidData, "No certificate found in PEM file")
    })
}

/// Load private key from PEM file
pub fn load_key_pem(path: &str) -> Result<PrivateKeyDer<'static>, std::io::Error> {
    let pem_data = std::fs::read(path)?;
    let mut reader = &pem_data[..];

    // Try PKCS#8 first
    if let Ok(keys) = rustls_pemfile::pkcs8_private_keys(&mut reader).collect::<Result<Vec<_>, _>>() {
        if let Some(key) = keys.into_iter().next() {
            return Ok(PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key)));
        }
    }

    // Try RSA
    let mut reader = &pem_data[..];
    if let Ok(keys) = rustls_pemfile::rsa_private_keys(&mut reader).collect::<Result<Vec<_>, _>>() {
        if let Some(key) = keys.into_iter().next() {
            return Ok(PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key)));
        }
    }

    Err(std::io::Error::new(
        std::io::ErrorKind::InvalidData,
        "No private key found in PEM file",
    ))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_localhost_cert() {
        let cert = CertificateChain::localhost().expect("Failed to generate localhost cert");
        assert!(!cert.cert.is_empty());
        assert!(!cert.key.secret_bytes().is_empty());
    }

    #[test]
    fn test_domain_cert() {
        let cert = CertificateChain::for_domain("example.com").expect("Failed to generate cert");
        assert!(!cert.cert.is_empty());
    }
}
