{"content":"//! TLS configuration for QUIC server with rustls
//!
//! Provides server and client TLS configurations with ALPN support for H2/H3

use super::alpn::AlpnProtocol;
use super::cert::CertificateChain;
use rustls::pki_types::PrivateKeyDer;
use rustls::ServerConfig;
use std::sync::Arc;

/// TLS configuration for QUIC server
pub struct TlsConfig {
    /// Certificate chain
    pub cert_chain: CertificateChain,
    /// ALPN protocols to advertise
    pub alpn_protocols: Vec<AlpnProtocol>,
    /// Enable session tickets for 0-RTT
    pub enable_0rtt: bool,
    /// Minimum TLS version (always 1.3 for QUIC)
    pub min_version: rustls::ProtocolVersion,
}

impl Default for TlsConfig {
    fn default() -> Self {
        Self {
            cert_chain: CertificateChain::localhost().expect("Failed to generate default cert"),
            alpn_protocols: AlpnProtocol::supported_protocols(),
            enable_0rtt: false,
            min_version: rustls::ProtocolVersion::TLSv1_3,
        }
    }
}

impl TlsConfig {
    /// Create new TLS config with custom ALPN protocols
    pub fn with_alpn(protocols: Vec<AlpnProtocol>) -> Self {
        Self {
            alpn_protocols: protocols,
            ..Default::default()
        }
    }

    /// Create new TLS config with custom certificate
    pub fn with_cert(cert_chain: CertificateChain) -> Self {
        Self {
            cert_chain,
            ..Default::default()
        }
    }

    /// Create new TLS config for a specific domain
    pub fn for_domain(domain: &str) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        Ok(Self {
            cert_chain: CertificateChain::for_domain(domain)?,
            ..Default::default()
        })
    }

    /// Enable 0-RTT session resumption
    pub fn with_0rtt(mut self) -> Self {
        self.enable_0rtt = true;
        self
    }

    /// Build rustls server configuration
    pub fn build_server_config(&self) -> Result<Arc<ServerConfig>, rustls::Error> {
        let mut config = ServerConfig::builder()
            .with_protocol_versions(&[self.min_version])?
            .with_no_client_auth()
            .with_single_cert(
                self.cert_chain.to_rustls_certs(),
                self.cert_chain.to_rustls_key(),
            )?;

        // Set ALPN protocols
        config.alpn_protocols = AlpnProtocol::to_alpn_vec(&self.alpn_protocols);

        // Configure session tickets for 0-RTT if enabled
        if self.enable_0rtt {
            config.session_storage = Arc::new(rustls::server::ServerSessionMemoryCache::new(256));
        }

        Ok(Arc::new(config))
    }

    /// Build rustls client configuration (for testing)
    pub fn build_client_config(&self) -> Result<Arc<rustls::ClientConfig>, rustls::Error> {
        let mut config = rustls::ClientConfig::builder()
            .with_protocol_versions(&[self.min_version])?
            .dangerous()
            .with_custom_certificate_verifier(Arc::new(NoServerVerification::new()))
            .with_no_client_auth();

        // Set ALPN protocols for client
        config.alpn_protocols = AlpnProtocol::to_alpn_vec(&self.alpn_protocols);

        Ok(Arc::new(config))
    }

    /// Get ALPN protocols as wire format
    pub fn alpn_wire_formats(&self) -> Vec<Vec<u8>> {
        self.alpn_protocols
            .iter()
            .map(|p| p.as_bytes().to_vec())
            .collect()
    }
}

/// Insecure certificate verifier for testing (disables certificate verification)
/// ONLY USE FOR TESTING/DEVELOPMENT
struct NoServerVerification {
    _private: (),
}

impl NoServerVerification {
    fn new() -> Self {
        Self { _private: () }
    }
}

impl rustls::client::danger::ServerCertVerifier for NoServerVerification {
    fn verify_server_cert(
        &self,
        _end_entity: &rustls::pki_types::CertificateDer<'_>,
        _intermediates: &[rustls::pki_types::CertificateDer<'_>],
        _server_name: &rustls::pki_types::ServerName,
        _ocsp_response: &[u8],
        _now: rustls::pki_types::UnixTime,
    ) -> Result<rustls::client::danger::ServerCertVerified, rustls::Error> {
        Ok(rustls::client::danger::ServerCertVerified::assertion())
    }

    fn verify_tls12_signature(
        &self,
        _message: &[u8],
        _cert: &rustls::pki_types::CertificateDer<'_>,
        _dss: &rustls::DigitallySignedStruct,
    ) -> Result<rustls::client::danger::HandshakeSignatureValid, rustls::Error> {
        Ok(rustls::client::danger::HandshakeSignatureValid::assertion())
    }

    fn verify_tls13_signature(
        &self,
        _message: &[u8],
        _cert: &rustls::pki_types::CertificateDer<'_>,
        _dss: &rustls::DigitallySignedStruct,
    ) -> Result<rustls::client::danger::HandshakeSignatureValid, rustls::Error> {
        Ok(rustls::client::danger::HandshakeSignatureValid::assertion())
    }

    fn supported_verify_schemes(&self) -> Vec<rustls::SignatureScheme> {
        vec![
            rustls::SignatureScheme::RSA_PKCS1_SHA256,
            rustls::SignatureScheme::RSA_PKCS1_SHA384,
            rustls::SignatureScheme::RSA_PKCS1_SHA512,
            rustls::SignatureScheme::ECDSA_NISTP256_SHA256,
            rustls::SignatureScheme::ECDSA_NISTP384_SHA384,
            rustls::SignatureScheme::ECDSA_NISTP521_SHA512,
            rustls::SignatureScheme::RSA_PSS_SHA256,
            rustls::SignatureScheme::RSA_PSS_SHA384,
            rustls::SignatureScheme::RSA_PSS_SHA512,
            rustls::SignatureScheme::ED25519,
            rustls::SignatureScheme::ED448,
        ]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_default_config() {
        let config = TlsConfig::default();
        assert!(config.alpn_protocols.contains(&AlpnProtocol::H3));
        assert!(config.alpn_protocols.contains(&AlpnProtocol::HqInterop));
    }

    #[test]
    fn test_custom_alpn() {
        let config = TlsConfig::with_alpn(vec![AlpnProtocol::H3, AlpnProtocol::H2]);
        assert_eq!(config.alpn_protocols.len(), 2);
    }

    #[test]
    fn test_server_config_build() {
        let tls_config = TlsConfig::default();
        let server_config = tls_config.build_server_config();
        assert!(server_config.is_ok());
    }

    #[test]
    fn test_client_config_build() {
        let tls_config = TlsConfig::default();
        let client_config = tls_config.build_client_config();
        assert!(client_config.is_ok());
    }
}
