{"content":"//! QUIC Server with TLS and H2/H3 support using Quinn
//!
//! This module provides a production-ready QUIC server implementation using:
//! - Quinn for QUIC protocol handling
//! - Rustls for TLS 1.3 encryption
//! - ALPN negotiation for H2/H3 protocol selection
//!
//! The server hosts the UI test pattern assets (index.html, index.css, bw_test_pattern.png)
//! over HTTP/3 with proper TLS encryption.

use quinn::{Connection, Endpoint, Incoming, RecvStream, SendStream};
use rustls::ServerConfig;
use std::net::SocketAddr;
use std::sync::Arc;
use tokio::io::{AsyncReadExt, AsyncWriteExt};

use super::tls::{TlsConfig, AlpnProtocol};

/// QUIC Server with TLS support
pub struct QuicTlsServer {
    endpoint: Endpoint,
    addr: SocketAddr,
}

impl QuicTlsServer {
    /// Bind and create a new QUIC TLS server
    pub async fn bind(addr: SocketAddr) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let tls_config = TlsConfig::default();
        let server_config = tls_config.build_server_config()?;

        Self::bind_with_config(addr, server_config).await
    }

    /// Bind with custom TLS configuration
    pub async fn bind_with_config(
        addr: SocketAddr,
        server_config: Arc<ServerConfig>,
    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let mut server_config = quinn::ServerConfig::with_crypto(server_config);

        // Configure ALPN
        server_config.alpn_protocols = vec![
            b"h3".to_vec(),
            b"hq-interop".to_vec(),
            b"htxquic".to_vec(),
        ];

        // Create endpoint
        let mut endpoint = Endpoint::server(server_config, addr)?;

        // Enable UDP segmentation offload for better performance
        if let Ok(socket) = endpoint.local_addr() {
            log::info!("🔒 QUIC TLS Server listening on {}", socket);
        }

        let actual_addr = endpoint.local_addr()?;

        Ok(Self {
            endpoint,
            addr: actual_addr,
        })
    }

    /// Bind with custom domain certificate
    pub async fn bind_domain(
        addr: SocketAddr,
        domain: &str,
    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let tls_config = TlsConfig::for_domain(domain)?;
        let server_config = tls_config.build_server_config()?;
        Self::bind_with_config(addr, server_config).await
    }

    /// Get server address
    pub fn local_addr(&self) -> SocketAddr {
        self.addr
    }

    /// Accept incoming connections
    pub async fn accept(&mut self) -> Option<Incoming> {
        self.endpoint.accept().await
    }

    /// Run the server loop, handling incoming connections
    pub async fn run(&mut self) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        log::info!("🚀 QUIC TLS Server running on {}", self.addr);
        log::info!("📡 ALPN protocols: h3, hq-interop, htxquic");

        while let Some(incoming) = self.accept().await {
            tokio::spawn(async move {
                match incoming.await {
                    Ok(connection) => {
                        log::info!("✅ New QUIC connection from {}", connection.remote_address());
                        if let Err(e) = handle_connection(connection).await {
                            log::error!("❌ Connection error: {}", e);
                        }
                    }
                    Err(e) => {
                        log::error!("❌ Incoming connection error: {}", e);
                    }
                }
            });
        }

        Ok(())
    }

    /// Close the server gracefully
    pub async fn close(&self) {
        self.endpoint.close(
            std::time::Duration::from_secs(1),
            b"server shutting down",
        );
    }
}

/// Handle a single QUIC connection
async fn handle_connection(connection: Connection) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let alpn = connection.handshake_data()?.alpn;
    let alpn_str = String::from_utf8_lossy(&alpn);

    log::info!("📡 ALPN negotiated: {}", alpn_str);

    // Accept streams based on ALPN protocol
    match alpn.as_slice() {
        b"h3" | b"hq-interop" | b"htxquic" => {
            // HTTP/3 or QUIC-native protocol
            handle_h3_stream(connection).await?;
        }
        _ => {
            log::warn!("⚠️  Unknown ALPN protocol: {}", alpn_str);
        }
    }

    Ok(())
}

/// Handle HTTP/3 style bidirectional streams
async fn handle_h3_stream(connection: Connection) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    while let Ok((send, recv)) = connection.accept_bi().await {
        let connection_id = connection.stable_id();
        tokio::spawn(async move {
            if let Err(e) = handle_h3_request(connection_id, send, recv).await {
                log::error!("Stream error: {}", e);
            }
        });
    }

    Ok(())
}

/// Handle a single HTTP/3 request-response cycle
async fn handle_h3_request(
    _connection_id: i32,
    mut send: SendStream,
    mut recv: RecvStream,
) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    // Read request
    let mut request_buf = Vec::new();
    recv.read_to_end(&mut request_buf).await?;

    let request_str = String::from_utf8_lossy(&request_buf);
    log::info!("📄 Received request: {}", request_str.trim());

    // Parse request path (simple parsing for demo)
    let path = parse_request_path(&request_str);
    log::info!("📁 Request path: {}", path);

    // Serve appropriate content
    let response = serve_content(&path);

    // Send response
    send.write_all(response.as_bytes()).await?;
    send.finish().await?;

    log::info!("✅ Sent {} bytes response", response.len());

    Ok(())
}

/// Parse HTTP request path
fn parse_request_path(request: &str) -> &str {
    // Simple parsing: "GET /path HTTP/3"
    if let Some(start) = request.find(' ') {
        let rest = &request[start + 1..];
        if let Some(end) = rest.find(' ') {
            return &rest[..end];
        }
    }
    "/"
}

/// Serve content based on path
fn serve_content(path: &str) -> String {
    match path {
        "/" | "/index.html" => {
            match std::fs::read_to_string("index.html") {
                Ok(content) => format_http3_response(200, "text/html", &content),
                Err(_) => format_http3_response(404, "text/html", "<h1>404 Not Found</h1>"),
            }
        }
        "/index.css" => {
            match std::fs::read_to_string("index.css") {
                Ok(content) => format_http3_response(200, "text/css", &content),
                Err(_) => format_http3_response(404, "text/plain", "/* CSS not found */"),
            }
        }
        "/bw_test_pattern.png" => {
            match std::fs::read("bw_test_pattern.png") {
                Ok(content) => {
                    // For binary content, we need to handle differently
                    // This is a simplified version
                    format!("HTTP/3 200 OK\r\nContent-Type: image/png\r\nContent-Length: {}\r\n\r\n", content.len())
                }
                Err(_) => format_http3_response(404, "text/plain", "Image not found"),
            }
        }
        _ => format_http3_response(404, "text/plain", "404 Not Found"),
    }
}

/// Format HTTP/3 response
fn format_http3_response(status: u16, content_type: &str, body: &str) -> String {
    let status_text = match status {
        200 => "OK",
        404 => "Not Found",
        500 => "Internal Server Error",
        _ => "Unknown",
    };

    format!(
        "HTTP/3 {} {}\r\nContent-Type: {}\r\nContent-Length: {}\r\n\r\n{}",
        status,
        status_text,
        content_type,
        body.len(),
        body
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_request_path() {
        assert_eq!(parse_request_path("GET / HTTP/3"), "/");
        assert_eq!(parse_request_path("GET /index.css HTTP/3"), "/index.css");
        assert_eq!(parse_request_path("POST /api HTTP/3"), "/api");
    }

    #[test]
    fn test_format_response() {
        let response = format_http3_response(200, "text/html", "<h1>Hello</h1>");
        assert!(response.contains("HTTP/3 200 OK"));
        assert!(response.contains("Content-Type: text/html"));
    }
}
