{"content":"//! QUIC TLS Server Binary with H2/H3 support
//!
//! This binary runs a QUIC server with TLS 1.3 encryption and ALPN negotiation
//! for HTTP/3 (h3), HTTP/2 (h2), and custom protocols.
//!
//! # Usage
//!
//! ```bash
//! # Run with default settings (localhost:4433)
//! cargo run --bin quic_tls_server --features tls-quic
//!
//! # Run with custom port
//! cargo run --bin quic_tls_server --features tls-quic -- --port 8443
//!
//! # Run with custom domain
//! cargo run --bin quic_tls_server --features tls-quic -- --domain example.com
//! ```

use clap::Parser;
use literbike::quic::QuicTlsServer;
use std::net::SocketAddr;
use tokio::signal;

#[derive(Parser, Debug)]
#[command(author, version, about = "QUIC TLS Server with H2/H3 support", long_about = None)]
struct Args {
    /// Bind address
    #[arg(short, long, default_value = "0.0.0.0")]
    bind: String,

    /// Port number
    #[arg(short, long, default_value = "4433")]
    port: u16,

    /// Domain name for certificate
    #[arg(short, long, default_value = "localhost")]
    domain: String,

    /// Enable verbose logging
    #[arg(short, long)]
    verbose: bool,

    /// Enable 0-RTT session resumption
    #[arg(long)]
    zero_rtt: bool,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let args = Args::parse();

    // Initialize logging
    if args.verbose {
        std::env::set_var("RUST_LOG", "debug");
    } else {
        std::env::set_var("RUST_LOG", "info");
    }
    env_logger::init();

    let addr: SocketAddr = format!("{}:{}", args.bind, args.port).parse()?;

    println!("🔒 QUIC TLS Server");
    println!("=================");
    println!("Bind: {}", addr);
    println!("Domain: {}", args.domain);
    println!("0-RTT: {}", if args.zero_rtt { "enabled" } else { "disabled" });
    println!();

    // Create server with domain-specific certificate
    let mut server = if args.domain != "localhost" {
        println!("📜 Generating certificate for {}...", args.domain);
        QuicTlsServer::bind_domain(addr, &args.domain).await?
    } else {
        println!("📜 Generating self-signed certificate for localhost...");
        QuicTlsServer::bind(addr).await?
    };

    let server_addr = server.local_addr();
    println!("✅ Server listening on {}", server_addr);
    println!();
    println!("📡 ALPN Protocols:");
    println!("   - h3 (HTTP/3 over QUIC)");
    println!("   - hq-interop (QUIC interop testing)");
    println!("   - htxquic (HTX over QUIC)");
    println!();
    println!("🧪 Test with curl:");
    println!("   curl -k --http3 https://{}:{}/", args.bind, args.port);
    println!();
    println!("🛑 Press Ctrl+C to stop");
    println!();

    // Run server with graceful shutdown
    tokio::select! {
        result = server.run() => {
            if let Err(e) = result {
                eprintln!("❌ Server error: {}", e);
                std::process::exit(1);
            }
        }
        _ = signal::ctrl_c() => {
            println!();
            println!("🛑 Shutting down...");
            server.close().await;
            println!("✅ Server stopped");
        }
    }

    Ok(())
}
