{"file_path":"/Users/jim/work/literbike/src/quic/tls/cert.rs","new_string":"//! Self-signed certificate generation for QUIC server testing
//!
//! Uses rcgen to generate X.509 certificates with TLS 1.3 support

use rustls::pki_types::{CertificateDer, PrivateKeyDer, PrivatePkcs8KeyDer};
use std::sync::Arc;

/// Certificate chain with private key for TLS
pub struct CertificateChain {
    /// End-entity certificate
    pub cert: CertificateDer<'static>,
    /// Private key (PKCS#8 format)
    pub key: PrivateKeyDer<'static>,
    /// Optional intermediate certificates
    pub intermediates: Vec<CertificateDer<'static>>,
}

impl CertificateChain {
    /// Generate a self-signed certificate for localhost testing
    pub fn localhost() -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let mut cert_params = rcgen::CertificateParams::new(vec![
            "localhost".to_string(),
            "127.0.0.1".to_string(),
            "::1".to_string(),
        ])?;

        // Set subject alternative names
        cert_params.subject_alt_names = vec![
            rcgen::SanType::DnsName("localhost".to_string()),
            rcgen::SanType::IpAddress(std::net::IpAddr::V4(std::net::Ipv4Addr::LOCALHOST)),
            rcgen::SanType::IpAddress(std::net::IpAddr::V6(std::net::Ipv6Addr::LOCALHOST)),
        ];

        let cert = cert_params.self_signed()?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Generate a self-signed certificate for a specific domain
    pub fn for_domain(domain: &str) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let mut cert_params = rcgen::CertificateParams::new(vec![domain.to_string()])?;
        cert_params.subject_alt_names = vec![
            rcgen::SanType::DnsName(domain.to_string()),
        ];

        let cert = cert_params.self_signed()?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Generate a self-signed certificate with custom subject alternative names
    pub fn with_san(sans: Vec<String>) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let mut cert_params = rcgen::CertificateParams::new(sans.clone())?;
        cert_params.subject_alt_names = sans
            .into_iter()
            .map(|s| rcgen::SanType::DnsName(s))
            .collect();

        let cert = cert_params.self_signed()?;
        let cert_der = cert.serialize_der()?;
        let key_der = cert.serialize_private_key_der();

        Ok(Self {
            cert: CertificateDer::from(cert_der),
            key: PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der)),
            intermediates: Vec::new(),
        })
    }

    /// Get certificate chain as rustls format
    pub fn to_rustls_certs(&self) -> Vec<CertificateDer<'static>> {
        let mut certs = vec![self.cert.clone()];
        certs.extend(self.intermediates.iter().cloned());
        certs
