        let actual_addr = endpoint.local_addr()?;

        Ok(Self {
            endpoint,
            addr: actual_addr,
        })
    }

    /// Get server address
    pub fn local_addr(&self) -> SocketAddr {
        self.addr
    }

    /// Accept incoming connections
    pub async fn accept(&mut self) -> Option<quinn::Incoming> {
        self.endpoint.accept().await
    }

    /// Run the server loop
    pub async fn run(&mut self) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        log::info!("🚀 QUIC TLS Server running on {}", self.addr);
        log::info!("📡 ALPN protocols: h3, hq-interop, htxquic, h2");

        while let Some(incoming) = self.accept().await {
            tokio::spawn(async move {
                match incoming.await {
                    Ok(connection) => {
                        log::info!("✅ New QUIC connection from {}", connection.remote_address());
                        if let Err(e) = handle_connection(connection).await {
                            log::error!("❌ Connection error: {}", e);
                        }
                    }
                    Err(e) => {
                        log::error!("❌ Incoming connection error: {}", e);
                    }
                }
            });
        }

        Ok(())
    }

    /// Close the server gracefully
    pub async fn close(&self) {
        self.endpoint.close(
            std::time::Duration::from_secs(1),
            b"server shutting down",
        );
    }
}

/// Handle a single QUIC connection
async fn handle_connection(connection: Connection) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    // Get ALPN from connection
    let alpn = connection.handshake_data().await?.alpn;
    let alpn_str = String::from_utf8_lossy(&alpn);
    log::info!("📡 ALPN negotiated: {}", alpn_str);

    // Accept streams
    while let Ok((send, recv)) = connection.accept_bi().await {
        tokio::spawn(async move {
            if let Err(e) = handle_request(send, recv).await {
                log::error!("Stream error: {}", e);
            }
        });
    }

    Ok(())
}

/// Handle a request-response cycle
async fn handle_request(
    mut send: SendStream,
    mut recv: RecvStream,
) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let mut request_buf = Vec::new();
    recv.read_to_end(&mut request_buf).await?;

    let request_str = String::from_utf8_lossy(&request_buf);
    log::info!("📄 Request: {}", request_str.trim());

    let path = parse_path(&request_str);
    let response = serve_content(&path);

    send.write_all(response.as_bytes()).await?;
    send.finish().await?;

    log::info!("✅ Sent {} bytes", response.len());
    Ok(())
}

fn parse_path(request: &str) -> &str {
    if let Some(start) = request.find(' ') {
        let rest = &request[start + 1..];
        if let Some(end) = rest.find(' ') {
            return &rest[..end];
        }
    }
    "/"
}

fn serve_content(path: &str) -> String {
    match path {
        "/" | "/index.html" => {
            std::fs::read_to_string("index.html")
                .map(|c| format_response(200, "text/html", &c))
                .unwrap_or_else(|_| format_response(404, "text/html", "<h1>404</h1>"))
        }
        "/index.css" => {
            std::fs::read_to_string("index.css")
                .map(|c| format_response(200, "text/css", &c))
                .unwrap_or_else(|_| format_response(404, "text/plain", "/* not found */"))
        }
        "/bw_test_pattern.png" => {
            std::fs::read("bw_test_pattern.png")
                .map(|data| format!("HTTP/3 200 OK\r\nContent-Type: image/png\r\nContent-Length: {}\r\n\r\n", data.len()))
                .unwrap_or_else(|_| format_response(404, "text/plain", "Image not found"))
        }
        _ => format_response(404, "text/plain", "404 Not Found"),
    }
}

fn format_response(status: u16, content_type: &str, body: &str) -> String {
    let status_text = match status {
        200 => "OK",
        404 => "Not Found",
        _ => "Unknown",
    };
    format!(
        "HTTP/3 {} {}\r\nContent-Type: {}\r\nContent-Length: {}\r\n\r\n{}",
        status, status_text, content_type, body.len(), body
    )
}
