    /// Enable verbose logging
    #[arg(short, long)]
    verbose: bool,
}

fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let args = Args::parse();

    // Initialize logging
    if args.verbose {
        std::env::set_var("RUST_LOG", "debug");
    } else {
        std::env::set_var("RUST_LOG", "info");
    }
    env_logger::init();

    let addr: SocketAddr = format!("{}:{}", args.bind, args.port).parse()?;

    println!("🔒 QUIC TLS Server");
    println!("=================");
    println!("Bind: {}", addr);
    println!("Domain: {}", args.domain);
    println!();

    // Create TLS terminator
    let tls = if args.domain != "localhost" {
        println!("📜 Generating certificate for {}...", args.domain);
        TlsTerminator::domain(&args.domain)?
    } else {
        println!("📜 Generating self-signed certificate for localhost...");
        TlsTerminator::localhost()?
    };

    println!("✅ TLS Terminator ready");
    println!();
    println!("📡 ALPN Protocols:");
    for proto in tls.alpn_protocols() {
        println!("   - {}", String::from_utf8_lossy(&proto));
    }
    println!();
    println!("🧪 Test with curl:");
    println!("   curl -k --http3 https://{}:{}/", args.bind, args.port);
    println!("   curl -k --http2 https://{}:{}/", args.bind, args.port);
    println!();
    println!("📝 TLS Configuration:");
    println!("   - TLS 1.3 only");
    println!("   - Certificate: self-signed for {}", args.domain);
    println!("   - ALPN negotiation: enabled");
    println!();
    println!("✨ QUIC server with TLS is ready for integration");
    println!("   See src/quic/quic_server.rs for UDP socket handling");
    println!("   TLS termination integrates with existing QUIC engine");

    Ok(())
}
